INSERT INTO public.exercises(course_id,module_id,slug,title,exercise_type,brief_md,starter_files,expected_result_md,hints,solution_md,order_index,estimated_minutes,is_published)
SELECT c.id,m.id,e.slug,e.title,e.exercise_type,e.brief_md,e.starter_files,e.expected_result_md,e.hints,e.solution_md,0,e.estimated_minutes,FALSE
FROM course_row c JOIN module_rows m ON TRUE JOIN exercise_seed e ON e.module_order=m.order_index
ON CONFLICT(course_id,slug) DO UPDATE SET module_id=EXCLUDED.module_id,title=EXCLUDED.title,exercise_type=EXCLUDED.exercise_type,brief_md=EXCLUDED.brief_md,starter_files=EXCLUDED.starter_files,expected_result_md=EXCLUDED.expected_result_md,hints=EXCLUDED.hints,solution_md=EXCLUDED.solution_md,estimated_minutes=EXCLUDED.estimated_minutes,is_published=FALSE;

WITH c AS (SELECT id FROM public.courses WHERE slug='machine-learning-python'),
resources(module_order,slug,title,summary,content_md,ord) AS (VALUES (0,'scikit-learn-getting-started','Scikit-learn : démarrage','Guide officiel scikit-learn','# Ressource officielle\n\n[Scikit-learn : démarrage](https://scikit-learn.org/stable/getting_started.html)',0),(1,'scikit-learn-preprocessing','Prétraitement','Guide officiel du prétraitement','# Ressource officielle\n\n[Prétraitement](https://scikit-learn.org/stable/modules/preprocessing.html)',1),(2,'scikit-learn-feature-selection','Sélection de variables','Guide officiel de sélection','# Ressource officielle\n\n[Sélection de variables](https://scikit-learn.org/stable/modules/feature_selection.html)',2),(3,'scikit-learn-linear-model','Modèles linéaires','Guide officiel des modèles linéaires','# Ressource officielle\n\n[Modèles linéaires](https://scikit-learn.org/stable/modules/linear_model.html)',3),(4,'scikit-learn-model-evaluation','Évaluation des modèles','Guide officiel des métriques','# Ressource officielle\n\n[Évaluation des modèles](https://scikit-learn.org/stable/modules/model_evaluation.html)',4),(5,'scikit-learn-ensemble','Méthodes d’ensemble','Guide officiel des ensembles','# Ressource officielle\n\n[Méthodes d’ensemble](https://scikit-learn.org/stable/modules/ensemble.html)',5),(6,'scikit-learn-imbalanced','Classes déséquilibrées','Guide sur les métriques et pondérations','# Ressource officielle\n\n[Classes déséquilibrées](https://scikit-learn.org/stable/modules/classes.html)',6),(7,'scikit-learn-compose','Pipelines et composition','Guide officiel Pipeline et ColumnTransformer','# Ressource officielle\n\n[Pipelines et composition](https://scikit-learn.org/stable/modules/compose.html)',7),(8,'scikit-learn-grid-search','Optimisation','Guide officiel du tuning','# Ressource officielle\n\n[Optimisation](https://scikit-learn.org/stable/modules/grid_search.html)',8),(9,'scikit-learn-inspection','Inspection des modèles','Guide officiel d’interprétabilité','# Ressource officielle\n\n[Inspection des modèles](https://scikit-learn.org/stable/inspection.html)',9),(10,'scikit-learn-calibration','Calibration','Guide officiel de calibration','# Ressource officielle\n\n[Calibration](https://scikit-learn.org/stable/modules/calibration.html)',10),(11,'model-cards','Model Cards','Référence sur la documentation responsable','# Ressource officielle\n\n[Model Cards](https://modelcards.withgoogle.com/about)',11))
INSERT INTO public.theory_resources(course_id,module_id,slug,title,summary,content_md,resource_type,order_index,is_published)
SELECT c.id,m.id,r.slug,r.title,r.summary,r.content_md,'reference',r.ord,FALSE
FROM c JOIN resources r ON TRUE JOIN public.modules m ON m.course_id=c.id AND m.order_index=r.module_order
ON CONFLICT(course_id,slug) DO UPDATE SET module_id=EXCLUDED.module_id,title=EXCLUDED.title,summary=EXCLUDED.summary,content_md=EXCLUDED.content_md,resource_type=EXCLUDED.resource_type,order_index=EXCLUDED.order_index,is_published=FALSE;

DO $$
DECLARE exercise_count INT; resource_count INT; module_exercises INT; published_exercises INT; published_resources INT;
BEGIN
 SELECT COUNT(*),COUNT(DISTINCT e.module_id),COUNT(*) FILTER (WHERE e.is_published)
 INTO exercise_count,module_exercises,published_exercises
 FROM public.exercises e JOIN public.courses c ON c.id=e.course_id WHERE c.slug='machine-learning-python';
 SELECT COUNT(*),COUNT(*) FILTER (WHERE r.is_published) INTO resource_count,published_resources
 FROM public.theory_resources r JOIN public.courses c ON c.id=r.course_id WHERE c.slug='machine-learning-python';
 IF exercise_count<>12 OR module_exercises<>12 OR resource_count<>12 OR published_exercises<>0 OR published_resources<>0 THEN
  RAISE EXCEPTION 'Chantier 4 Machine Learning incomplet: exercices %, modules %, ressources %, exercices publiés %, ressources publiées %',exercise_count,module_exercises,resource_count,published_exercises,published_resources;
 END IF;
END $$;
